mapper.update:
UPDATE items
SET current_cnt = current_cnt + #{cnt}
WHERE id = #{itemId}

UPDATE items
SET current_cnt = current_cnt - #{cnt}
WHERE id = #{itemId}

mapper.select:
SELECT h.id, h.date, i.item_name, h.cnt, h.customer, h.customer_tel, h.type, h.price, h.created_at, h.cust_num, h.address FROM item_history h left join items i on h.item_idx = i.id WHERE 1=1
AND h.date between #{startDate} and #{endDate}
AND h.item_name like concat('%',#{itemName},'%')
AND h.customer like concat('%',#{customer},'%')
AND h.type = #{type}
ORDER BY created_at desc

